CREATE OR REPLACE FUNCTION public.clean_cpf(cpf_text text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
    cleaned text;
BEGIN
    -- Remove tudo que nao for numero
    cleaned := regexp_replace(cpf_text, '[^0-9]', '', 'g');
    -- Retorna NULL se estiver vazio, senao retorna o CPF limpo
    IF cleaned = '' THEN RETURN NULL; END IF;
    RETURN cleaned;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_card_dashboard_metrics()
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_total_ativos INT;
    v_total_atraso INT;
    v_total_inativos INT;
    v_total_cancelados INT;
    v_total_base INT;

    v_vendas_mes_atual INT;
    v_vendas_mes_anterior INT;
    v_vendas_semana_atual INT;
    v_vendas_semana_anterior INT;

    v_churn_rate NUMERIC;

    -- Datas para comparações
    d_inicio_mes_atual DATE := date_trunc('month', CURRENT_DATE);
    d_inicio_mes_anterior DATE := date_trunc('month', CURRENT_DATE - INTERVAL '1 month');
    d_fim_mes_anterior DATE := date_trunc('month', CURRENT_DATE) - INTERVAL '1 second';

    d_inicio_semana_atual DATE := date_trunc('week', CURRENT_DATE) - INTERVAL '1 day'; -- Ajuste para Domingo se necessário
    d_inicio_semana_anterior DATE := d_inicio_semana_atual - INTERVAL '7 days';
    d_fim_semana_anterior DATE := d_inicio_semana_atual - INTERVAL '1 second';
BEGIN
    -- 1. Primeiro, garantimos que os status estão atualizados
    -- Isso garante que o dashboard mostre a realidade do momento
    PERFORM sync_client_statuses();

    -- 2. Contagem da Base (Filtrando Planos Relevantes)
    SELECT 
        COUNT(*) FILTER (WHERE status = 'ATIVO'),
        COUNT(*) FILTER (WHERE status = 'ATRASO'),
        COUNT(*) FILTER (WHERE status = 'INATIVO'),
        COUNT(*) FILTER (WHERE status = 'CANCELADO')
    INTO 
        v_total_ativos,
        v_total_atraso,
        v_total_inativos,
        v_total_cancelados
    FROM clients
    WHERE plano IN ('Bim Familiar', 'Bim Individual');

    v_total_base := v_total_ativos + v_total_atraso + v_total_inativos + v_total_cancelados;

    -- 3. Cálculo de Churn (Cancelados / Base Total)
    IF v_total_base > 0 THEN
        v_churn_rate := ROUND((v_total_cancelados::numeric / v_total_base) * 100, 2);
    ELSE
        v_churn_rate := 0;
    END IF;

    -- 4. Vendas (Mês)
    SELECT COUNT(*) INTO v_vendas_mes_atual
    FROM clients
    WHERE plano IN ('Bim Familiar', 'Bim Individual')
    AND created_at >= d_inicio_mes_atual;

    SELECT COUNT(*) INTO v_vendas_mes_anterior
    FROM clients
    WHERE plano IN ('Bim Familiar', 'Bim Individual')
    AND created_at >= d_inicio_mes_anterior AND created_at <= d_fim_mes_anterior;

    -- 5. Vendas (Semana)
    SELECT COUNT(*) INTO v_vendas_semana_atual
    FROM clients
    WHERE plano IN ('Bim Familiar', 'Bim Individual')
    AND created_at >= d_inicio_semana_atual;

    SELECT COUNT(*) INTO v_vendas_semana_anterior
    FROM clients
    WHERE plano IN ('Bim Familiar', 'Bim Individual')
    AND created_at >= d_inicio_semana_anterior AND created_at <= d_fim_semana_anterior;

    -- 6. Montar Retorno JSON
    RETURN json_build_object(
        'ativos', v_total_ativos,
        'atraso', v_total_atraso,
        'inativos', v_total_inativos, -- Novo campo pedido
        'cancelados', v_total_cancelados,
        'churn_rate', v_churn_rate,
        'vendas_mes', json_build_object(
            'atual', v_vendas_mes_atual,
            'anterior', v_vendas_mes_anterior
        ),
        'vendas_semana', json_build_object(
            'atual', v_vendas_semana_atual,
            'anterior', v_vendas_semana_anterior
        )
    );
END;
$function$

CREATE OR REPLACE FUNCTION public.get_card_metrics()
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_result            json;
    v_semana_inicio     date := date_trunc('week', current_date)::date;
    v_semana_ant_inicio date := (date_trunc('week', current_date) - interval '7 days')::date;
    v_semana_ant_fim    date := date_trunc('week', current_date)::date - 1;
    v_mes_inicio        date := date_trunc('month', current_date)::date;
    v_mes_ant_inicio    date := date_trunc('month', current_date - interval '1 month')::date;
    v_mes_ant_fim       date := (date_trunc('month', current_date) - interval '1 day')::date;
    v_total_ativos       bigint;
    v_total_atraso       bigint;
    v_taxa_inadimplencia numeric;
    v_tempo_medio_atraso numeric;
BEGIN
    -- Totais
    SELECT
        COUNT(*) FILTER (WHERE status = 'ATIVO'),
        COUNT(*) FILTER (WHERE status = 'ATRASO')
    INTO v_total_ativos, v_total_atraso
    FROM clients
    WHERE plano IN ('Bim Familiar', 'Bim Individual');

    v_taxa_inadimplencia := COALESCE(
        ROUND(
            (v_total_atraso::numeric / NULLIF((v_total_ativos + v_total_atraso), 0)) * 100,
        2), 0);

    -- Tempo médio de atraso
    SELECT COALESCE(
        ROUND(AVG(current_date - ap.due_date)::numeric, 0), 0)
    INTO v_tempo_medio_atraso
    FROM asaas_payments ap
    JOIN clients c ON c.id = ap.client_id
    WHERE ap.status = 'OVERDUE'
      AND ap.due_date < current_date
      AND c.plano IN ('Bim Familiar', 'Bim Individual');

    SELECT json_build_object(
        'total_ativos', v_total_ativos,
        'novos_semana', json_build_object(
            'current',  COALESCE((SELECT COUNT(*) FROM clients WHERE created_at::date >= v_semana_inicio AND plano IN ('Bim Familiar', 'Bim Individual')), 0),
            'previous', COALESCE((SELECT COUNT(*) FROM clients WHERE created_at::date >= v_semana_ant_inicio AND created_at::date <= v_semana_ant_fim AND plano IN ('Bim Familiar', 'Bim Individual')), 0)
        ),
        'novos_mes', json_build_object(
            'current',  COALESCE((SELECT COUNT(*) FROM clients WHERE created_at::date >= v_mes_inicio AND plano IN ('Bim Familiar', 'Bim Individual')), 0),
            'previous', COALESCE((SELECT COUNT(*) FROM clients WHERE created_at::date >= v_mes_ant_inicio AND created_at::date <= v_mes_ant_fim AND plano IN ('Bim Familiar', 'Bim Individual')), 0)
        ),
        'taxa_inadimplencia', v_taxa_inadimplencia,
        'tempo_medio_atraso', v_tempo_medio_atraso
    ) INTO v_result;
    RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_clinic_overview_new()
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_result            json;
    v_hoje              date := current_date;
    v_ontem             date := current_date - 1;
    v_semana_inicio     date := date_trunc('week', current_date)::date;
    v_semana_ant_inicio date := (date_trunc('week', current_date) - interval '7 days')::date;
    v_semana_ant_fim    date := date_trunc('week', current_date)::date - 1;
    v_mes_inicio        date := date_trunc('month', current_date)::date;
    v_mes_ant_inicio    date := date_trunc('month', current_date - interval '1 month')::date;
    v_mes_ant_fim       date := (date_trunc('month', current_date) - interval '1 day')::date;
    v_cap_min_dia_util  int  := 660;
    v_cap_min_sabado    int  := 300;
    v_duracao_media_min int  := 30;
    v_slots_mes         int;
    v_consultas_mes_cnt int;
BEGIN
    SELECT
        SUM(CASE
            WHEN EXTRACT(DOW FROM gs.d) BETWEEN 1 AND 5 THEN v_cap_min_dia_util / v_duracao_media_min
            WHEN EXTRACT(DOW FROM gs.d) = 6 THEN v_cap_min_sabado / v_duracao_media_min
            ELSE 0
        END)
    INTO v_slots_mes
    FROM generate_series(v_mes_inicio, (date_trunc('month', current_date) + interval '1 month - 1 day')::date, '1 day'::interval) AS gs(d);

    SELECT COUNT(*) INTO v_consultas_mes_cnt
    FROM appointments
    WHERE appointment_date >= v_mes_inicio
      AND appointment_date < v_mes_inicio + interval '1 month'
      AND status = 'finalizado';

    SELECT json_build_object(
        'consultas_hoje',
            (SELECT COUNT(*) FROM appointments WHERE appointment_date = v_hoje AND status != 'cancelado'),
        'consultas_ontem',
            (SELECT COUNT(*) FROM appointments WHERE appointment_date = v_ontem AND status != 'cancelado'),
        'consultas_semana', json_build_object(
            'current', (SELECT COUNT(*) FROM appointments WHERE appointment_date >= v_semana_inicio AND appointment_date < v_semana_inicio + 7 AND status != 'cancelado'),
            'previous', (SELECT COUNT(*) FROM appointments WHERE appointment_date >= v_semana_ant_inicio AND appointment_date <= v_semana_ant_fim AND status != 'cancelado')
        ),
        'consultas_mes', json_build_object(
            'current',  v_consultas_mes_cnt,
            'previous', (SELECT COUNT(*) FROM appointments WHERE appointment_date >= v_mes_ant_inicio AND appointment_date <= v_mes_ant_fim AND status != 'cancelado')
        ),
        'taxa_ocupacao', CASE WHEN v_slots_mes > 0 THEN ROUND((v_consultas_mes_cnt::numeric / v_slots_mes) * 100, 1) ELSE 0 END
    ) INTO v_result;
    RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.login(email_param text, password_param text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  usr record;
  token_payload json;
begin
  select * from public.users where email = email_param into usr;

  if usr is null then
    return '{"error": "Usuário não encontrado", "status": 404}';
  end if;

  -- Compara a senha enviada com o hash armazenado usando a extensão pgcrypto
  if usr.password_hash = crypt(password_param, usr.password_hash) then
    -- Se a senha estiver correta, prepara o payload do token
    token_payload := json_build_object(
      'userId', usr.id,
      'roleId', usr.role_id
    );
    return json_build_object('payload', token_payload, 'status', 200);
  else
    -- Se a senha estiver incorreta
    return '{"error": "Senha incorreta", "status": 401}';
  end if;
end;
$function$

CREATE OR REPLACE FUNCTION public.remove_duplicate_cpfs()
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    r RECORD;
    kept_id BIGINT;
    duplicate_id BIGINT;
    moved_dependents INT := 0;
    moved_appointments INT := 0;
    deleted_clients INT := 0;
BEGIN
    -- Loop para cada CPF que aparece mais de uma vez
    FOR r IN
        SELECT 
            cpf, 
            -- Array com IDs ordenados por data de criação (o primeiro é o mais antigo/original)
            array_agg(id ORDER BY created_at ASC) as ids
        FROM 
            public.clients
        WHERE 
            cpf IS NOT NULL 
            AND cpf <> '' 
            AND length(cpf) > 5 -- Evita CPFs inválidos muito curtos
        GROUP BY 
            cpf
        HAVING 
            count(*) > 1
    LOOP
        -- O ID que vamos MANTER é o primeiro (mais antigo)
        kept_id := r.ids[1];

        -- Itera sobre os outros IDs (duplicados) para processá-los
        FOR i IN 2 .. array_length(r.ids, 1) LOOP
            duplicate_id := r.ids[i];

            -- 1. Transfere DEPENDENTES do duplicado para o original
            UPDATE public.dependents
            SET titular_id = kept_id
            WHERE titular_id = duplicate_id;

            GET DIAGNOSTICS moved_dependents = ROW_COUNT;

            -- 2. Transfere AGENDAMENTOS do duplicado para o original
            UPDATE public.appointments
            SET client_id = kept_id
            WHERE client_id = duplicate_id;

            GET DIAGNOSTICS moved_appointments = ROW_COUNT;

            -- 3. Deleta o cliente duplicado
            DELETE FROM public.clients
            WHERE id = duplicate_id;

            deleted_clients := deleted_clients + 1;
        END LOOP;
    END LOOP;

    -- Retorna um resumo do que foi feito
    RETURN json_build_object(
        'status', 'success',
        'message', 'Limpeza concluída com sucesso.',
        'deleted_clients', deleted_clients
    );

EXCEPTION WHEN OTHERS THEN
    -- Em caso de erro, desfaz tudo (rollback automático da função)
    RETURN json_build_object(
        'status', 'error',
        'message', SQLERRM
    );
END;
$function$

CREATE OR REPLACE FUNCTION public.sync_single_client_status(p_client_id bigint)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_status TEXT;
    v_client RECORD;
    v_latest_payment RECORD;
BEGIN
    -- Buscar dados do cliente
    SELECT id, status, plano INTO v_client
    FROM clients
    WHERE id = p_client_id;

    IF NOT FOUND THEN
        RETURN;
    END IF;

    -- Se for plano não mensal, não altera
    IF v_client.plano NOT IN ('Bim Familiar', 'Bim Individual') THEN
        RETURN;
    END IF;

    -- Buscar o pagamento mais recente do cliente
    SELECT 
        status,
        due_date,
        payment_date
    INTO v_latest_payment
    FROM asaas_payments
    WHERE client_id = p_client_id
    ORDER BY due_date DESC, created_at DESC
    LIMIT 1;

    -- Determinar o status com base no pagamento mais recente
    IF v_latest_payment IS NULL THEN
        v_status := 'PENDENTE';
    ELSE
        CASE v_latest_payment.status
            WHEN 'RECEIVED' THEN
                v_status := 'ATIVO';

            WHEN 'PENDING' THEN
                IF v_latest_payment.due_date < CURRENT_DATE THEN
                    IF v_latest_payment.due_date < (CURRENT_DATE - INTERVAL '30 days') THEN
                        v_status := 'INATIVO';
                    ELSE
                        v_status := 'ATRASO';
                    END IF;
                ELSE
                    v_status := 'ATIVO';
                END IF;

            WHEN 'OVERDUE' THEN
                IF v_latest_payment.due_date < (CURRENT_DATE - INTERVAL '30 days') THEN
                    v_status := 'INATIVO';
                ELSE
                    v_status := 'ATRASO';
                END IF;

            WHEN 'CANCELED' THEN
                v_status := 'CANCELADO';

            ELSE
                v_status := 'ATIVO';
        END CASE;
    END IF;

    -- Atualizar o status do cliente se necessário
    IF v_client.status != v_status THEN
        UPDATE clients 
        SET status = v_status,
            updated_at = NOW()
        WHERE id = p_client_id;

        -- Log da alteração
        INSERT INTO action_logs (action, details, user_email, created_at)
        VALUES (
            'CLIENT_STATUS_UPDATED',
            jsonb_build_object(
                'client_id', p_client_id,
                'old_status', v_client.status,
                'new_status', v_status,
                'reason', 'payment_change'
            ),
            'system',
            NOW()
        );
    END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.trigger_sanitize_client_data()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Normaliza Nome
    IF NEW.nome IS NOT NULL THEN
        NEW.nome := public.normalize_name_text(NEW.nome);
    END IF;

    -- Normaliza Sobrenome
    IF NEW.sobrenome IS NOT NULL THEN
        NEW.sobrenome := public.normalize_name_text(NEW.sobrenome);
    END IF;

    -- Limpa Telefone
    IF NEW.telefone IS NOT NULL THEN
        NEW.telefone := public.only_numbers(NEW.telefone);
    END IF;

    -- Limpa CPF
    IF NEW.cpf IS NOT NULL THEN
        NEW.cpf := public.only_numbers(NEW.cpf);
    END IF;

    -- Normaliza Email
    IF NEW.email IS NOT NULL THEN
        NEW.email := LOWER(TRIM(NEW.email));
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.trigger_update_client_status_on_payment_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_client_status TEXT;
BEGIN
    -- Se o pagamento tem um client_id, atualiza apenas aquele cliente
    IF NEW.client_id IS NOT NULL OR OLD.client_id IS NOT NULL THEN
        -- Chama a função de sincronização apenas para este cliente
        PERFORM public.sync_single_client_status(COALESCE(NEW.client_id, OLD.client_id));
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.update_appointments_with_client_id()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
rec RECORD;
found_id BIGINT;
updated_count INT := 0;
BEGIN
-- Percorre cada agendamento na sua tabela que ainda não tem um client_id
FOR rec IN SELECT id, patient_name FROM public.appointments WHERE client_id IS NULL LOOP
-- Para cada agendamento, procura por um cliente com o nome correspondente
SELECT c.id INTO found_id
FROM public.clients c
WHERE normalize_name(c.nome || ' ' || c.sobrenome) = normalize_name(rec.patient_name)
LIMIT 1; -- Pega apenas o primeiro resultado para evitar erros

    -- Se um cliente for encontrado (found_id não é nulo), atualiza o agendamento
    IF found_id IS NOT NULL THEN
        UPDATE public.appointments
        SET client_id = found_id
        WHERE id = rec.id;
        updated_count := updated_count + 1;
    END IF;
END LOOP;

RETURN 'Atualização concluída. ' || updated_count || ' agendamentos foram vinculados a clientes.';

END;
$function$
